"""ACAR V5 Stage-1B pinned DSP preprocessing config (pure/stdlib). The config is FIXED in code (not generated by the trainer) and
canonicalized → preprocessing_config_sha256. The real mne DSP (Stage-1B run) must produce windows conforming to this exactly.
"""
from __future__ import annotations
import hashlib
import json

# exact 19-channel 10-20 order (the substrate montage)
CHANNELS_19 = ("Fp1", "Fp2", "F7", "F3", "Fz", "F4", "F8", "T3", "C3", "Cz", "C4", "T4", "T5", "P3", "Pz", "P4", "T6", "O1", "O2")

PREPROCESSING_CONFIG = {
    "schema": "acar_v5_preprocessing_v1",
    "channels": list(CHANNELS_19),          # exact set AND order
    "n_channels": 19,
    "resample_hz": 128,
    "bandpass_hz": [0.5, 45.0],
    "window_sec": 4.0,
    "window_samples": 512,                  # 4 s × 128 Hz
    "window_overlap": 0.0,                   # non-overlapping (pinned)
    "reference": "average",                  # pinned re-reference policy
    "notch_hz": None,                        # explicitly none
    "units": "microvolt",
    "trial_normalization": "per_trial_zscore",
    "bad_channel_policy": "fail_closed",     # missing / duplicate canonical channel → fail
    # the 19 canonical channels must all be PRESENT (missing → fail) and are picked + reordered to the canonical order;
    # extra non-canonical channels are dropped; a duplicated canonical channel fails closed. Code (real_mne_reader) matches this.
    "required_channels": "all_19_canonical_present",
    "extra_channel_policy": "drop_non_canonical_after_required_19_present",
    "duplicate_channel_policy": "fail_closed",
    "channel_output_order": "canonical_pinned",
    # Stage-1B10: the OUTPUT montage stays the old-10-20 canonical order above; a PINNED input-channel alias layer maps common
    # modern 10-10 temporal names to the same historical electrodes BEFORE the canonical pick (input names are stripped +
    # case-normalized, so Fp1/FP1/fp1 collapse). Extra channels are still dropped; two raw channels mapping to the same logical
    # channel FAIL. This makes old-name and modern-name cohorts semantically symmetric without changing the trained layout.
    "logical_montage_policy": "old_10_20_canonical_with_reviewed_10_10_aliases",
    "channel_alias_schema_version": "acar_v5_channel_alias_v1",
    "input_channel_aliases": {"T7": "T3", "T8": "T4", "P7": "T5", "P8": "T6"},
    "duplicate_logical_channel_policy": "fail_closed",
    # Stage-1B11: reviewed montage-COMPLETION policy — the canonical output montage is UNCHANGED (old-10-20); a small, per-cohort
    # WHITELISTED set of missing canonical electrodes may be interpolated (spherical-spline, standard positions) so the substrate's
    # 19-channel logical layout is preserved. Any missing channel NOT in the whitelist → FAIL. Duplicate logical channels are never
    # interpolated (fail-closed). Interpolation is audited (SubjectWindows.provenance + feature-dump policy hashes).
    "montage_completion_policy_version": "ACAR_V5_STAGE1B11_MONTAGE_COMPLETION_V1",
    "allowed_missing_by_cohort": {"ds004584": ["Pz"], "ds004000": ["F3", "F4", "P3", "P4"]},
    "max_interpolated_canonical_channels_per_recording": 4,
    "interpolation_method": "mne_interpolate_bads_spherical_spline_standard_1020",
    "interpolation_mode": "accurate",
    "min_donor_channels": 8,
    "donor_policy": ("good_position_eeg_channels_only;interpolated_channels_not_donors;"
                     "noncanonical_donors_dropped_after_canonical_output;unknown_position_channels_ignored"),
}


def _subset_sha256(keys):
    import hashlib
    sub = {k: PREPROCESSING_CONFIG[k] for k in keys}
    return hashlib.sha256(json.dumps(sub, sort_keys=True, separators=(",", ":")).encode()).hexdigest()


def channel_alias_policy_sha256():
    """Hash of ONLY the channel-alias policy subset (for provenance/feature-dump auditing)."""
    return _subset_sha256(("channels", "input_channel_aliases", "logical_montage_policy", "channel_alias_schema_version",
                           "duplicate_logical_channel_policy", "channel_output_order"))


def montage_completion_policy_sha256():
    """Hash of ONLY the montage-completion policy subset (for provenance/feature-dump auditing)."""
    return _subset_sha256(("montage_completion_policy_version", "allowed_missing_by_cohort",
                           "max_interpolated_canonical_channels_per_recording", "interpolation_method",
                           "interpolation_mode", "min_donor_channels", "donor_policy"))


def canonical_json():
    return json.dumps(PREPROCESSING_CONFIG, sort_keys=True, separators=(",", ":"))


def config_sha256():
    return hashlib.sha256(canonical_json().encode()).hexdigest()
